import { describe, expect, it } from 'vitest';
import { buildNodeSingleClickSelectionResult } from '../../../../src/webview/components/graph/interaction/nodeSingleClickSelection';

function makeOptions(overrides: Partial<Parameters<typeof buildNodeSingleClickSelectionResult>[0]> = {}) {
  return {
    clientX: 10,
    clientY: 20,
    ctrlKey: false,
    label: 'Node',
    metaKey: false,
    nodeId: 'node-a',
    now: 123,
    selectedNodeIds: [],
    shiftKey: false,
    ...overrides,
  };
}

describe('graph/interaction/nodeSingleClickSelection', () => {
  it('selects and previews the node when no modifiers are pressed', () => {
    expect(buildNodeSingleClickSelectionResult(makeOptions())).toEqual({
      nextLastClick: {
        nodeId: 'node-a',
        time: 123,
      },
      effects: [
        { kind: 'selectOnlyNode', nodeId: 'node-a' },
        { kind: 'previewNode', nodeId: 'node-a' },
      ],
    });
  });

  it('toggles multi-selection when a modifier is pressed', () => {
    expect(
      buildNodeSingleClickSelectionResult(
        makeOptions({
          ctrlKey: true,
          selectedNodeIds: ['node-b'],
        }),
      ),
    ).toEqual({
      nextLastClick: {
        nodeId: 'node-a',
        time: 123,
      },
      effects: [
        { kind: 'setSelection', nodeIds: ['node-b', 'node-a'] },
      ],
    });
  });

  it('clears selection and focused file when clicking the only selected node', () => {
    expect(
      buildNodeSingleClickSelectionResult(
        makeOptions({
          selectedNodeIds: ['node-a'],
        }),
      ),
    ).toEqual({
      nextLastClick: null,
      effects: [
        { kind: 'clearSelection' },
        { kind: 'clearFocusedFile' },
      ],
    });
  });
});

import { describe, expect, it } from 'vitest';
import {
  getNodeContextMenuSelection,
  toggleNodeSelection,
} from '../../../../src/webview/components/graph/interaction/nodeSelection';

describe('graph/interaction node selection', () => {
  it('adds a node when toggling a node that is not selected', () => {
    expect(toggleNodeSelection('src/app.ts', ['src/utils.ts'])).toEqual([
      'src/utils.ts',
      'src/app.ts',
    ]);
  });

  it('removes a node when toggling a node that is already selected', () => {
    expect(toggleNodeSelection('src/app.ts', ['src/app.ts', 'src/utils.ts'])).toEqual([
      'src/utils.ts',
    ]);
  });

  it('keeps the current selection when right-clicking an already selected node', () => {
    expect(getNodeContextMenuSelection('src/app.ts', ['src/app.ts', 'src/utils.ts'])).toEqual({
      nodeIds: ['src/app.ts', 'src/utils.ts'],
      shouldUpdateSelection: false,
    });
  });

  it('selects only the target node when right-clicking an unselected node', () => {
    expect(getNodeContextMenuSelection('src/app.ts', ['src/utils.ts'])).toEqual({
      nodeIds: ['src/app.ts'],
      shouldUpdateSelection: true,
    });
  });
});
